function solve(points: number[][]): number {
    const n = points.length;
    const slopeMap: Map<string, number[]> = new Map();

    // Precompute all pairs of points and their slopes
    for (let i = 0; i < n; i++) {
        for (let j = i + 1; j < n; j++) {
            const [x1, y1] = points[i];
            const [x2, y2] = points[j];
            let slope: string;
            if (y2 - y1 === 0) {
                slope = "inf"; // Horizontal line
            } else {
                slope = (x2 - x1) / (y2 - y1).toString();
            }
            if (!slopeMap.has(slope)) {
                slopeMap.set(slope, []);
            }
            slopeMap.get(slope)!.push(i);
        }
    }

    let count = 0;

    // Check for each pair of points (as a line) how many other pairs of points have the same slope
    for (const [slope, indices] of slopeMap.entries()) {
        const len = indices.length;
        for (let i = 0; i < len; i++) {
            for (let j = i + 1; j < len; j++) {
                const p1 = indices[i];
                const p2 = indices[j];
                const p3 = indices[i + 1];
                const p4 = indices[j + 1];
                // Check if the four points form a trapezoid
                // We need to ensure that the four points are distinct
                if (p1 !== p2 && p1 !== p3 && p1 !== p4 && p2 !== p3 && p2 !== p4 && p3 !== p4) {
                    count++;
                }
            }
        }
    }

    return count;
}

