            }
            if _, exists := slopeMap[slope]; !exists {
                slopeMap[slope] = []int{}
            }
            slopeMap[slope] = append(slopeMap[slope], i)
        }
    }

    var count int64
    // Check for each pair of points (as a line) how many other pairs of points have the same slope
    for slope, indices := range slopeMap {
        lenIndices := len(indices)
        for i := 0; i < lenIndices; i++ {
            for j := i + 1; j < lenIndices; j++ {
                p1 := indices[i]
                p2 := indices[j]
                p3 := indices[i+1]
                p4 := indices[j+1]
                // Check if the four points are distinct
                if p1 != p2 && p1 != p3 && p1 != p4 && p2 != p3 && p2 != p4 && p3 != p4 {
                    count++
                }
            }
        }
    }

    return count
}
